 local Round = function(num) return math.floor(num + 0.5) end local function SetPercent(self, val, max, penaltypercent, ...) local owner = self.owner local health = owner and owner.components.health if health and health.GetMax then max = Round(health:GetMax()) end return self.dycOldSetPercent(self, val, max, penaltypercent, ...) end local function DYCHealthBadge(self) self.dycOldSetPercent = self.SetPercent self.SetPercent = SetPercent end return DYCHealthBadge 